import{_ as t,c as o,o as r,a1 as l}from"./chunks/framework.9hXSu8bi.js";const a="/mypatterndocs/static/%E7%B3%BB%E7%BB%9F%E6%97%A5%E5%BF%97-%E7%99%BB%E5%BD%95%E6%97%A5%E5%BF%97.B3IsK9rP.png",i="/mypatterndocs/static/%E7%B3%BB%E7%BB%9F%E6%97%A5%E5%BF%97-%E6%93%8D%E4%BD%9C%E6%97%A5%E5%BF%97.bcIfxnV0.png",n="/mypatterndocs/static/%E7%B3%BB%E7%BB%9F%E6%97%A5%E5%BF%97-%E6%9B%B4%E6%96%B0%E6%97%A5%E5%BF%97.B31Z6fRt.png",s="/mypatterndocs/static/%E7%B3%BB%E7%BB%9F%E6%97%A5%E5%BF%97-%E9%A2%84%E8%AD%A6%E5%8F%82%E6%95%B0%E5%8F%98%E6%9B%B4.CtOgPkWv.png",E=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/系统日志.md","filePath":"zh/帮助文档/功能介绍/系统日志.md"}'),e={name:"zh/帮助文档/功能介绍/系统日志.md"},g=l('<h2 id="系统日志" tabindex="-1">系统日志 <a class="header-anchor" href="#系统日志" aria-label="Permalink to &quot;系统日志&quot;">​</a></h2><blockquote><p>系统日志页面用于记录平台内所有用户的操作行为、登录记录以及系统更新历史，支持多条件筛选查询，便于安全审计和问题追溯。</p></blockquote><h3 id="一、登录日志" tabindex="-1">一、登录日志 <a class="header-anchor" href="#一、登录日志" aria-label="Permalink to &quot;一、登录日志&quot;">​</a></h3><blockquote><p>登录日志记录所有用户的登录登出行为，包括登录时间、IP地址、操作结果等，用于监控账号安全。</p></blockquote><p><img src="'+a+'" alt="" data-fancybox="gallery"></p><h4 id="_1-登录日志搜索栏" tabindex="-1">1. 登录日志搜索栏 <a class="header-anchor" href="#_1-登录日志搜索栏" aria-label="Permalink to &quot;1. 登录日志搜索栏&quot;">​</a></h4><ul><li><strong>搜索日志</strong>：输入关键词（如日志内容、操作人等）进行模糊搜索。</li><li><strong>手机号</strong>：按输入的手机号进行模糊匹配搜索。</li><li><strong>创建时间</strong>：选择时间范围，筛选指定时间段内的日志。</li><li><strong>查询</strong>：点击后根据设置的筛选条件搜索登录日志。</li><li><strong>重置</strong>：清空所有筛选条件，恢复默认显示。</li></ul><h4 id="_2-日志列表" tabindex="-1">2. 日志列表 <a class="header-anchor" href="#_2-日志列表" aria-label="Permalink to &quot;2. 日志列表&quot;">​</a></h4><ul><li><strong>+</strong>：展开或收起更多详情信息。</li><li><strong>日志内容</strong>：登录操作的具体描述，如“用户名: user3, 登录成功！”或“用户名: user3, 退出成功！”。</li><li><strong>操作人ID</strong>：执行登录操作的用户账号ID。</li><li><strong>操作人</strong>：执行登录操作的用户姓名。</li><li><strong>IP</strong>：登录来源的IP地址。</li><li><strong>手机号</strong>：登录用户的手机号。</li><li><strong>创建时间</strong>：登录或退出操作发生的具体时间。</li></ul><h3 id="二、操作日志" tabindex="-1">二、操作日志 <a class="header-anchor" href="#二、操作日志" aria-label="Permalink to &quot;二、操作日志&quot;">​</a></h3><blockquote><p>操作日志记录用户在系统内执行的所有关键操作，如项目创建、配置修改、数据上传等，用于追溯用户行为。</p></blockquote><p><img src="'+i+'" alt="" data-fancybox="gallery"></p><h4 id="_1-操作日志搜索栏" tabindex="-1">1. 操作日志搜索栏 <a class="header-anchor" href="#_1-操作日志搜索栏" aria-label="Permalink to &quot;1. 操作日志搜索栏&quot;">​</a></h4><ul><li><strong>搜索日志</strong>：输入关键词（如日志内容、操作人等）进行模糊搜索。</li><li><strong>手机号</strong>：按输入的手机号进行模糊匹配搜索。</li><li><strong>创建时间</strong>：选择时间范围，筛选指定时间段内的日志。</li><li><strong>查询</strong>：点击后根据设置的筛选条件搜索操作日志。</li><li><strong>重置</strong>：清空所有筛选条件，恢复默认显示。</li></ul><h4 id="_2-日志列表-1" tabindex="-1">2. 日志列表 <a class="header-anchor" href="#_2-日志列表-1" aria-label="Permalink to &quot;2. 日志列表&quot;">​</a></h4><ul><li><strong>+</strong>：展开或收起更多详情信息。</li><li><strong>日志内容</strong>：操作的具体内容，如“子项目-编辑”、“预警用户-添加”。</li><li><strong>操作人ID</strong>：操作用户的账号ID。</li><li><strong>操作人</strong>：操作用户的姓名。</li><li><strong>IP</strong>：操作来源IP。</li><li><strong>手机号</strong>：操作用户手机号。</li><li><strong>创建时间</strong>：操作时间。</li><li><strong>操作类型</strong>：操作的分类，如“添加”、“更新”、“删除”、“查询”等。</li></ul><h3 id="三、更新日志" tabindex="-1">三、更新日志 <a class="header-anchor" href="#三、更新日志" aria-label="Permalink to &quot;三、更新日志&quot;">​</a></h3><blockquote><p>更新日志记录系统版本的迭代信息，包括新增功能、优化改进、问题修复等，方便用户了解平台演进。</p></blockquote><p><img src="'+n+'" alt="" data-fancybox="gallery"></p><h4 id="_1-更新日志搜索栏" tabindex="-1">1. 更新日志搜索栏 <a class="header-anchor" href="#_1-更新日志搜索栏" aria-label="Permalink to &quot;1. 更新日志搜索栏&quot;">​</a></h4><ul><li><strong>搜索日志</strong>：输入关键词（如版本号、功能名称）搜索。</li><li><strong>手机号</strong>：更新操作人的手机号。</li><li><strong>创建时间</strong>：按更新时间范围筛选。</li><li><strong>查询</strong>：点击后根据设置的筛选条件搜索更新日志。</li><li><strong>重置</strong>：清空所有筛选条件，恢复默认显示。</li></ul><h4 id="_2-日志列表-2" tabindex="-1">2. 日志列表 <a class="header-anchor" href="#_2-日志列表-2" aria-label="Permalink to &quot;2. 日志列表&quot;">​</a></h4><ul><li><strong>+</strong>：展开或收起详情。</li><li><strong>更新内容</strong>：本次更新的具体描述，如“修改登录页标题”。</li><li><strong>操作人</strong>：发布更新日志的人员。</li><li><strong>更新时间</strong>：更新发布的日期时间。</li></ul><h3 id="四、预警参数变更日志" tabindex="-1">四、预警参数变更日志 <a class="header-anchor" href="#四、预警参数变更日志" aria-label="Permalink to &quot;四、预警参数变更日志&quot;">​</a></h3><blockquote><p>预警参数变更日志记录所有预警策略参数的修改历史，包括正向位移颜色条、正向速度颜色条、操作人手机等，用于追踪预警参数的变化过程，便于审计和回溯。</p></blockquote><p><img src="'+s+'" alt="" data-fancybox="gallery"></p><h4 id="_1-预警参数变更日志搜索栏" tabindex="-1">1. 预警参数变更日志搜索栏 <a class="header-anchor" href="#_1-预警参数变更日志搜索栏" aria-label="Permalink to &quot;1. 预警参数变更日志搜索栏&quot;">​</a></h4><ul><li><strong>子项目/预警策略名称</strong>：选择子项目或预警策略名称进行搜索。</li><li><strong>查询</strong>：点击后根据搜索条件筛选日志列表。</li><li><strong>重置</strong>：清空所有筛选条件，恢复默认显示。</li><li><strong>数据比较</strong>：勾选两条预警参数变更日志，点击后可对比查看两次变更的参数差异。</li></ul><h4 id="_2-日志列表-3" tabindex="-1">2. 日志列表 <a class="header-anchor" href="#_2-日志列表-3" aria-label="Permalink to &quot;2. 日志列表&quot;">​</a></h4><ul><li><strong>子项目/预警策略名称</strong>：参数变更的子项目或预警策略名称。</li><li><strong>版本号</strong>：预警参数版本变更的标识，每次变更后版本号递增。</li><li><strong>操作人手机</strong>：执行参数变更操作的用户手机号。</li><li><strong>创建时间</strong>：参数变更操作发生的具体时间。</li><li><strong>操作内容</strong>：</li></ul>',30),c=[g];function h(d,u,_,b,p,B){return r(),o("div",null,c)}const m=t(e,[["render",h]]);export{E as __pageData,m as default};
